// Generated by AI (DoXYZ agents). Do not edit directly.
// Summary: Tests Heading semantic element rendering, auto presets, explicit overrides, inherit handling, and utility states.

import '@testing-library/jest-dom';
import * as React from 'react';
import { render, screen } from '@testing-library/react';
import { Heading } from './Heading';

describe('Heading', () => {
  it('renders the requested heading level via the as prop', () => {
    render(<Heading as="h3">Semantic title</Heading>);
    expect(screen.getByText('Semantic title').tagName).toBe('H3');
  });

  describe('auto presets', () => {
    const cases: ReadonlyArray<{
      as: 'h1' | 'h2' | 'h3' | 'h4' | 'h5' | 'h6';
      level: number;
      sizeToken: string;
      weightToken: string;
    }> = [
      { as: 'h1', level: 1, sizeToken: 'text-2xl', weightToken: 'font-bold' },
      { as: 'h2', level: 2, sizeToken: 'text-2xl', weightToken: 'font-bold' },
      { as: 'h3', level: 3, sizeToken: 'text-2xl', weightToken: 'font-extrabold' },
      { as: 'h4', level: 4, sizeToken: 'text-xl', weightToken: 'font-bold' },
      { as: 'h5', level: 5, sizeToken: 'text-lg', weightToken: 'font-bold' },
      { as: 'h6', level: 6, sizeToken: 'text-base', weightToken: 'font-bold' }
    ];

    it.each(cases)('applies presets for %s when size and weight are auto', ({ as, level, sizeToken, weightToken }) => {
      render(
        <Heading as={as} size="auto" weight="auto">
          Preset
        </Heading>
      );
      const element = screen.getByRole('heading', { level, name: 'Preset' });
      const hasAllTokens = [sizeToken, weightToken].every((token) => element.className.includes(token));
      expect(hasAllTokens).toBe(true);
    });
  });

  it('omits preset size class when size is explicit', () => {
    render(
      <Heading as="h1" size="6xl" weight="auto">
        Explicit Size
      </Heading>
    );
    const element = screen.getByRole('heading', { level: 1, name: 'Explicit Size' });
    expect(element.className.includes('text-2xl')).toBe(false);
  });

  it('omits preset weight class when weight is explicit', () => {
    render(
      <Heading as="h3" size="auto" weight="light">
        Explicit Weight
      </Heading>
    );
    const element = screen.getByRole('heading', { level: 3, name: 'Explicit Weight' });
    expect(element.className.includes('font-extrabold')).toBe(false);
  });

  it('emits no variant classes for axes set to inherit', () => {
    render(
      <Heading
        as="h5"
        size="inherit"
        weight="inherit"
        align="inherit"
        color="inherit"
        transform="inherit"
      >
        Inherit Axis
      </Heading>
    );
    const element = screen.getByRole('heading', { level: 5, name: 'Inherit Axis' });
    const forbiddenTokens = [
      'text-lg',
      'font-bold',
      'text-left',
      'text-color-content-default',
      'normal-case',
      'uppercase',
      'lowercase',
      'capitalize'
    ];
    const hasTokens = forbiddenTokens.some((token) => element.className.includes(token));
    expect(hasTokens).toBe(false);
  });

  it('applies italic class when italic is true', () => {
    render(<Heading italic>Italicized</Heading>);
    expect(screen.getByText('Italicized').className.includes('italic')).toBe(true);
  });

  it('applies truncate class when truncate is true', () => {
    render(<Heading truncate>Truncated</Heading>);
    expect(screen.getByText('Truncated').className.includes('truncate')).toBe(true);
  });

  it('applies m-0 when noMargin is true', () => {
    render(<Heading noMargin>Marginless</Heading>);
    expect(screen.getByText('Marginless').className.includes('m-0')).toBe(true);
  });

  it('omits m-0 when noMargin is false', () => {
    render(
      <Heading noMargin={false}>
        Margin Default
      </Heading>
    );
    expect(screen.getByText('Margin Default').className.includes('m-0')).toBe(false);
  });
});
